-- Create "product_skus" table
CREATE TABLE "product_skus" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "sku_code" character varying NOT NULL,
  "sku_name" character varying NULL,
  "barcode" character varying NULL,
  "customer_sku" character varying NULL,
  "color" character varying NULL,
  "color_no" character varying NULL,
  "size" character varying NULL,
  "packaging_version" character varying NULL,
  "is_active" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "product_id" bigint NOT NULL,
  "default_unit_id" bigint NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "product_skus_products_product_skus" FOREIGN KEY ("product_id") REFERENCES "products" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "product_skus_units_product_skus" FOREIGN KEY ("default_unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE SET NULL
);
-- Create index "productsku_barcode" to table: "product_skus"
CREATE UNIQUE INDEX "productsku_barcode" ON "product_skus" ("barcode") WHERE ((barcode IS NOT NULL) AND ((barcode)::text <> ''::text));
-- Create index "productsku_color" to table: "product_skus"
CREATE INDEX "productsku_color" ON "product_skus" ("color");
-- Create index "productsku_color_no" to table: "product_skus"
CREATE INDEX "productsku_color_no" ON "product_skus" ("color_no");
-- Create index "productsku_customer_sku" to table: "product_skus"
CREATE INDEX "productsku_customer_sku" ON "product_skus" ("customer_sku");
-- Create index "productsku_product_id_is_active" to table: "product_skus"
CREATE INDEX "productsku_product_id_is_active" ON "product_skus" ("product_id", "is_active");
-- Create index "productsku_product_id_sku_code" to table: "product_skus"
CREATE UNIQUE INDEX "productsku_product_id_sku_code" ON "product_skus" ("product_id", "sku_code");
-- Create index "productsku_size" to table: "product_skus"
CREATE INDEX "productsku_size" ON "product_skus" ("size");
-- Create index "productsku_sku_code" to table: "product_skus"
CREATE UNIQUE INDEX "productsku_sku_code" ON "product_skus" ("sku_code");
-- Modify "inventory_lots" table
ALTER TABLE "inventory_lots" ADD COLUMN "product_sku_id" bigint NULL, ADD CONSTRAINT "inventory_lots_product_skus_inventory_lots" FOREIGN KEY ("product_sku_id") REFERENCES "product_skus" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION;
-- Create index "inventorylot_product_sku_id" to table: "inventory_lots"
CREATE INDEX "inventorylot_product_sku_id" ON "inventory_lots" ("product_sku_id");
-- Modify "sales_order_items" table
ALTER TABLE "sales_order_items" ADD COLUMN "product_sku_id" bigint NULL, ADD CONSTRAINT "sales_order_items_product_skus_sales_order_items" FOREIGN KEY ("product_sku_id") REFERENCES "product_skus" ("id") ON UPDATE NO ACTION ON DELETE SET NULL;
-- Create index "salesorderitem_product_sku_id" to table: "sales_order_items"
CREATE INDEX "salesorderitem_product_sku_id" ON "sales_order_items" ("product_sku_id");
-- Modify "shipment_items" table
ALTER TABLE "shipment_items" ADD COLUMN "product_sku_id" bigint NULL, ADD CONSTRAINT "shipment_items_product_skus_shipment_items" FOREIGN KEY ("product_sku_id") REFERENCES "product_skus" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION;
-- Create index "shipmentitem_product_sku_id" to table: "shipment_items"
CREATE INDEX "shipmentitem_product_sku_id" ON "shipment_items" ("product_sku_id");
-- Modify "stock_reservations" table
ALTER TABLE "stock_reservations" ADD COLUMN "product_sku_id" bigint NULL, ADD CONSTRAINT "stock_reservations_product_skus_stock_reservations" FOREIGN KEY ("product_sku_id") REFERENCES "product_skus" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION;
